# RUN AT THE VERY END (after Wave 9), then fix every FAILED/ERROR test to full green.
$log = "$env:TEMP\pytest_master.log"; cd "C:\Users\Admin\Machine learning\mlframe"; $env:PYTHONUNBUFFERED='1'; $env:PYTHONIOENCODING='utf-8'; $n = [int]([Math]::Max(1, [Math]::Floor((Get-CimInstance Win32_Processor | Measure-Object -Property NumberOfCores -Sum).Sum / 2))); Write-Host "Using -n $n (physical cores / 2)" -ForegroundColor Cyan; python.exe -m pytest tests/ -n $n --fast --dist=worksteal --max-worker-restart=20 --instafail --show-progress -p no:randomly -p no:cacheprovider --no-cov --tb=short --timeout=600 --maxfail=0 -ra -v --color=no 2>&1 | Tee-Object -FilePath $log; Write-Host "`nLog: $log" -ForegroundColor Cyan; $fails = Select-String -Path $log -Pattern ' FAILED$| ERROR$' -CaseSensitive; Write-Host "Failed/Errored ($($fails.Count)):" -ForegroundColor Yellow; $fails | ForEach-Object { Write-Host "  $($_.Line)" -ForegroundColor Red }
